mapper.select:
SELECT id, name, category, is_disabled, is_deleted, create_name, create_id, create_date, update_name, update_id, update_date FROM sp_supplier_pool WHERE is_deleted = 0
AND name LIKE CONCAT('%', #{name}, '%')
AND category = #{category}
AND is_disabled = #{isDisabled}
ORDER BY create_date DESC

mapper.update:
